import{_ as r,o as t,c as e,a2 as o}from"./chunks/framework.VxKNwi4m.js";const g=JSON.parse('{"title":"소송 사건 관리","description":"","frontmatter":{},"headers":[],"relativePath":"document/legal-case.md","filePath":"document/legal-case.md","lastUpdated":1783667317000}'),l={name:"document/legal-case.md"};function i(n,a,s,h,d,c){return t(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="소송-사건-관리" tabindex="-1">소송 사건 관리 <a class="header-anchor" href="#소송-사건-관리" aria-label="Permalink to &quot;소송 사건 관리&quot;">​</a></h1><p>프로젝트와 관련된 개별 소송 사건의 기초 정보(사건번호, 법원, 당사자, 진행 상태 등)를 등록하고, 소송의 전체 이력을 체계적으로 관리하는 페이지입니다.</p><ul><li><strong>위치</strong>: <code>프로젝트 문서 관리 &gt; 소송 사건 관리</code></li></ul><h2 id="개요" tabindex="-1">개요 <a class="header-anchor" href="#개요" aria-label="Permalink to &quot;개요&quot;">​</a></h2><p>&#39;소송 문서 관리&#39;가 소송 과정에서 발생하는 서류를 관리하는 곳이라면, **&#39;소송 사건 관리&#39;**는 그 서류들이 귀속되는 <strong>&#39;사건&#39; 자체의 마스터 데이터</strong>를 관리하는 곳입니다. 사건의 심급(1심, 2심, 3심), 관할 법원, 소송물 가액, 진행 상태 등을 기록하여 프로젝트의 법적 리스크 현황을 한눈에 파악할 수 있도록 돕습니다.</p><h2 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h2><ul><li><strong>사건 기초 정보 관리</strong>: 사건번호, 사건명, 법원, 원고/피고, 소가(소송가액) 등 핵심 정보 기록</li><li><strong>심급 및 진행 상태 추적</strong>: 1/2/3심 구분 및 &#39;진행 중&#39;, &#39;종결&#39;, &#39;취하&#39; 등 실시간 상태 관리</li><li><strong>연관 사건 연결</strong>: 본안 소송과 관련된 신청 사건(가압류, 가처분)이나 심급 간(항소, 상고) 사건을 서로 연결하여 이력 추적 지원</li><li><strong>상세 필터링</strong>: 관할 법원별, 소송 구분별, 진행 상태별 사건 목록 필터링</li><li><strong>엑셀 리포트</strong>: 관리 중인 소송 사건 전체 내역을 엑셀 파일로 추출하여 보고서로 활용</li><li><strong>권한 기반 접근</strong>: 민감한 법률 정보를 보호하기 위해 프로젝트별 쓰기 권한 및 접근 권한 제어</li></ul><h2 id="화면-구성" tabindex="-1">화면 구성 <a class="header-anchor" href="#화면-구성" aria-label="Permalink to &quot;화면 구성&quot;">​</a></h2><h3 id="_1-목록-제어-및-필터링" tabindex="-1">1. 목록 제어 및 필터링 <a class="header-anchor" href="#_1-목록-제어-및-필터링" aria-label="Permalink to &quot;1. 목록 제어 및 필터링&quot;">​</a></h3><p>관리 중인 사건을 효율적으로 찾기 위한 검색 영역입니다.</p><ul><li><strong>필터 컨트롤</strong>: 심급(Level), 사건 구분(Sort), 관할 법원(Court), 진행 여부(In Progress) 등 전문화된 소송 필터 제공</li><li><strong>검색 바</strong>: 사건명이나 사건번호, 상대방 성명 등으로 검색 가능</li></ul><h3 id="_2-소송-사건-목록" tabindex="-1">2. 소송 사건 목록 <a class="header-anchor" href="#_2-소송-사건-목록" aria-label="Permalink to &quot;2. 소송 사건 목록&quot;">​</a></h3><p>사건의 주요 요약 정보를 테이블 형태로 표시합니다.</p><ul><li><strong>주요 필드</strong>: 사건번호, 사건명, 법원, 진행 상태, 관련 당사자 정보</li><li><strong>빠른 필터</strong>: 목록 내의 법원 명칭이나 사건 구분 아이콘을 클릭하여 즉시 해당 조건으로 필터링할 수 있습니다.</li></ul><h3 id="_3-사건-상세-정보-view" tabindex="-1">3. 사건 상세 정보 (View) <a class="header-anchor" href="#_3-사건-상세-정보-view" aria-label="Permalink to &quot;3. 사건 상세 정보 (View)&quot;">​</a></h3><p>특정 사건의 모든 기록과 연결된 자원을 확인하는 화면입니다.</p><ul><li><strong>사건 요약</strong>: 사건의 모든 마스터 데이터와 현재까지의 진행 경과 표시</li><li><strong>연관 사건 리스트</strong>: 해당 사건과 연결된 상위/하위 심급이나 관련 사건 목록 표시</li><li><strong>첨부 자원</strong>: 사건 자체에 첨부된 기본 파일 및 참고 링크 리스트</li></ul><h3 id="_4-사건-등록-및-수정-form" tabindex="-1">4. 사건 등록 및 수정 (Form) <a class="header-anchor" href="#_4-사건-등록-및-수정-form" aria-label="Permalink to &quot;4. 사건 등록 및 수정 (Form)&quot;">​</a></h3><p>신규 소송 사건을 생성하거나 기존 정보를 업데이트하는 화면입니다.</p><ul><li><strong>입력 항목</strong>: 사건번호, 법원, 당사자 정보, 소가, 착수금/성공보수 등 비용 정보(필요 시), 사건 개요</li><li><strong>연관 사건 지정</strong>: 기존에 등록된 사건 중 관련이 있는 사건을 검색하여 상호 연결할 수 있습니다.</li></ul><h2 id="💡-주요-관리-포인트" tabindex="-1">💡 주요 관리 포인트 <a class="header-anchor" href="#💡-주요-관리-포인트" aria-label="Permalink to &quot;💡 주요 관리 포인트&quot;">​</a></h2><h3 id="사건번호-형식의-정확성" tabindex="-1">사건번호 형식의 정확성 <a class="header-anchor" href="#사건번호-형식의-정확성" aria-label="Permalink to &quot;사건번호 형식의 정확성&quot;">​</a></h3><p>사건번호(예: 2024가단123456)는 법원 시스템과의 대조 및 내부 검색의 기준이 되므로 오타 없이 정확하게 입력해야 합니다. 정확한 사건번호 입력은 차후 전자소송 시스템 연동이나 판례 검색 시 핵심적인 연결 고리가 됩니다.</p><h3 id="연관-사건-연결-기능-활용" tabindex="-1">연관 사건 연결 기능 활용 <a class="header-anchor" href="#연관-사건-연결-기능-활용" aria-label="Permalink to &quot;연관 사건 연결 기능 활용&quot;">​</a></h3><p>하나의 분쟁이 여러 심급으로 이어지거나 관련 신청 사건이 있을 경우, <strong>[관련 사건]</strong> 기능을 통해 이들을 서로 연결하십시오. 이를 통해 1심 판결이 2심으로 어떻게 이어졌는지, 혹은 본안 소송 전 가압류가 어떻게 진행되었는지에 대한 전체 맥락을 손쉽게 파악할 수 있습니다.</p><h3 id="진행-상태의-실시간-업데이트" tabindex="-1">진행 상태의 실시간 업데이트 <a class="header-anchor" href="#진행-상태의-실시간-업데이트" aria-label="Permalink to &quot;진행 상태의 실시간 업데이트&quot;">​</a></h3><p>소송은 장기간 진행되므로 판결문 접수나 취하 등 이벤트 발생 시 즉시 <strong>진행 상태</strong>를 업데이트해야 합니다. 이는 프로젝트 전체의 법적 우발 부채(Contingent Liabilities) 산정 및 리스크 관리에 중요한 기초 자료가 됩니다.</p><h3 id="엑셀-추출을-통한-보고" tabindex="-1">엑셀 추출을 통한 보고 <a class="header-anchor" href="#엑셀-추출을-통한-보고" aria-label="Permalink to &quot;엑셀 추출을 통한 보고&quot;">​</a></h3><p>정기적인 프로젝트 리스크 보고 시 상단의 [엑셀] 버튼을 활용하십시오. 수작업 없이도 현재 진행 중인 모든 소송 현황을 리포트 형식으로 즉시 생성할 수 있습니다.</p>',29)])])}const p=r(l,[["render",i]]);export{g as __pageData,p as default};
